var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"리브 경! 퇴로를 차단해 주세요!","JPN":"アレン卿！　退路を遮断してください！","ENG":"Dame Liv! Seal off any escape routes!","TWN":"莉芙卿！從後面包抄！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"오키도키! 나한테 맡기시라!","JPN":"りょーかい！　私に任せて！","ENG":"Okie dokie! You can leave it to me!","TWN":"Okie Dokie！包在我身上！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"기록 분석 완료. 제 행동반경이 지속적으로 좁아지고 있군요.","JPN":"記録分析完了。私の行動半径が徐々に狭くなっていますね。","ENG":"Record analysis complete. My freedom of maneuver continues to diminish.","TWN":"紀錄分析完畢，我的行動半徑持續縮小中。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"인간형 적을 상대로 체계적인 훈련을 받았다고 추정됩니다. 그림자 전문이라도 됩니까.","JPN":"人間型の敵を相手に体系的な訓練を受けたと推定されます。シャドウ専門なのですか。","ENG":"It leads me to hypothesize that you have received systematic combat training against humanoid adversaries. Is your expertise in hunting Shadows?","TWN":"推測曾經接受過對抗人型敵人的系統化訓練，可以說是專門對付暗影的嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"적의 질문에는 대답해 드릴 수가 없군요. 얌전히 투항하시면 자세하게 설명해 드리죠.","JPN":"敵の質問にはお答えできません。大人しく投降したら詳しく説明して差し上げましょう。","ENG":"I will not answer my enemy's question. I'd be happy to elucidate in detail if you surrender though.","TWN":"對於敵人的問題我們無可奉告，若是你乖乖就範，那我可以跟你詳細說明。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"절대 투항하지 마! 부단장한테 설명 듣다간 하루 종일 안 끝난다구!","JPN":"絶対投降しないで！　副団長が説明し始めたら一日じゃ終わらないんだよ！","ENG":"Don't do it! Unless you want to hear her talk for an entire day!","TWN":"你千萬不可以投降！副團長的說明很可能一整天都聽不完！！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"리브 경! 적과 싸우는 와중에 동료를 헐뜯다니요!","JPN":"アレン卿！　敵との戦闘中に同僚の悪口を言ってはいけませんよ！","ENG":"Dame Liv! How could you disparage your colleague in the middle of a fight?!","TWN":"莉芙卿！你竟然在和敵人交手時抹黑同伴！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"STUDENT_EXTRA_B_NULL","text":{"KOREA":"야, 저……. 저 사람들 광대라고 하지 않았냐?","JPN":"おい、ちょっと……あの人たちって道化だよね？","ENG":"Hey… Aren't those folks supposed to be clowns?","TWN":"喂……你不是說那些人是小丑嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"STUDENT_EXTRA_B_NULL","text":{"KOREA":"사실 엄청 강한 거 아냐? 좀 멋있어 보이는데……?","JPN":"実はすごく強いんじゃない？　ちょっとかっこよく見えるんだけど……？","ENG":"What if they're actually super strong? They're starting to look kinda cool to me…","TWN":"他們根本超強好不好？！看起來有點帥欸……？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"STUDENT_EXTRA_A_NULL","text":{"KOREA":"웃기지 마! 정규 태스크포스들도 깨졌다는데 돈도 없이 코스프레나 하는 컨셉 등신들이 어떻게 이겨!","JPN":"バカいうな！　正規タスクフォースカンパニーもボコられたのに、金ももらわないコスプレしかできないオタク集団がどうやって勝つんだよ！","ENG":"Don't be ridiculous! That girl beat even the legit TASKFORCEs, I hear. Those stupid cosplayers don't stand a chance!","TWN":"拜託！連正規特遣勢力都打輸她，\\n那些玩Cosplay的怎麼可能打得贏！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"STUDENT_EXTRA_A_NULL","text":{"KOREA":"저 애가 분명 영상에서 봤던 것처럼 쇠파이프로 개박살을 내 줄 거야! 그래야 우리 영상이 뜨지!","JPN":"ネットでみた映像みたいに、きっとあの子が鉄パイプでめちゃくちゃに\\nしてくれるよ！　そうしてくれなきゃ俺たちの動画の再生数が伸びないだろ！","ENG":"She'll kick their butts with her pipe, just as I saw in that other video! And then our video will go viral!","TWN":"那個女生一定會像影片裡看到的一樣，用鐵管打爆他們啦！這樣我們的影片才會爆紅啊！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"흠……. 평범한 공격으로는 저지하기 어려운가.","JPN":"ふむ……平凡な攻撃では阻止できないか。","ENG":"Hmm... It appears ordinary attacks won't stop her.","TWN":"嗯……普通的攻擊可能很難攔下她。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"부단장! 리브 경! 물러서도록!","JPN":"副団長！　リブ！　下がれ！","ENG":"Deputy! Dame Liv! Fall back!","TWN":"副團長！莉芙卿！閃開！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"고에너지 반응이 검출되었습니다. 이번 공격은 진심이군요.","JPN":"高エネルギー反応が検出されました。今回の攻撃は本気のようですね。","ENG":"High energy signature detected. You must be putting your heart and soul in this attack.","TWN":"檢測到高能量反應，看來這次的攻擊是認真的。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};